{"version":3,"file":"image-upload.js","sources":["components/node_modules/@tuniao/tnui-vue3-uniapp/components/image-upload/src/image-upload.vue","../uniComponent:/QzovVXNlcnMvMzU1NzcvRG93bmxvYWRzL2Vhc3lhaS11bmlhcHAtYWlnYy9zcmMvY29tcG9uZW50cy9ub2RlX21vZHVsZXMvQHR1bmlhby90bnVpLXZ1ZTMtdW5pYXBwL2NvbXBvbmVudHMvaW1hZ2UtdXBsb2FkL3NyYy9pbWFnZS11cGxvYWQudnVl"],"sourcesContent":["<script lang=\"ts\" setup>\nimport TnIcon from '../../icon/src/icon.vue'\nimport { useNamespace } from '../../../hooks'\nimport { imageUploadEmits, imageUploadProps } from './image-upload'\nimport { useImageUpload } from './composables'\n\nconst props = defineProps(imageUploadProps)\ndefineEmits(imageUploadEmits)\n\nconst ns = useNamespace('image-upload')\nconst nsItem = useNamespace('image-upload-item')\n\nconst {\n  fileList,\n  isExceedMaxCount,\n  chooseFile,\n  retryUploadFile,\n  retryAllUpload,\n  customUploadHandle,\n  removeFileEvent,\n  clearAllFile,\n  previewImage,\n} = useImageUpload(props)\n\ndefineExpose({\n  /**\n   * @description 手动选择文件\n   */\n  chooseFile,\n  /**\n   * @description 手动上传图片\n   */\n  upload: customUploadHandle,\n  /**\n   * @description 重新上传失败的文件\n   */\n  retry: retryAllUpload,\n  /**\n   * @description 清空所有文件\n   */\n  clear: clearAllFile,\n})\n</script>\n\n<template>\n  <view :class=\"[ns.b()]\">\n    <!-- 上传列表 -->\n    <view\n      v-for=\"(item, index) in fileList\"\n      :key=\"index\"\n      :class=\"[nsItem.b(), nsItem.is('custom', !!$slots.uploadImage)]\"\n    >\n      <slot name=\"uploadImage\" :data=\"item\">\n        <!-- 已上传图片 -->\n        <view\n          class=\"tn-gray-light_bg\"\n          :class=\"[\n            nsItem.e('image'),\n            nsItem.is('finish', item.status === 'done'),\n          ]\"\n          @tap.stop=\"previewImage(index)\"\n        >\n          <image class=\"image\" :src=\"item.url\" mode=\"aspectFill\" />\n        </view>\n        <!-- 删除按钮 -->\n        <view\n          v-if=\"showRemove && !disabled\"\n          :class=\"[nsItem.e('remove')]\"\n          @tap.stop=\"removeFileEvent(index)\"\n        >\n          <view :class=\"[nsItem.em('remove', 'icon')]\">\n            <TnIcon name=\"close-fill\" />\n          </view>\n        </view>\n        <!-- 重试蒙层 -->\n        <view\n          v-if=\"item.status === 'failed' && !disabled\"\n          :class=\"[nsItem.e('retry')]\"\n          @tap.stop=\"retryUploadFile(index)\"\n        >\n          <TnIcon name=\"refresh-simple\" />\n        </view>\n        <!-- 进度波浪 -->\n        <!-- 进度0 ~ 100 => -300 ~ -400 -->\n        <view\n          v-if=\"\n            showUploadProgress &&\n            item.progress > 0 &&\n            item.progress < 100 &&\n            !disabled\n          \"\n          :class=\"[\n            nsItem.e('progress'),\n            nsItem.is('finish', item.progress === 100),\n          ]\"\n        >\n          <view\n            :class=\"[nsItem.em('progress', 'wave')]\"\n            :style=\"{ top: `${-300 - item.progress}%` }\"\n          />\n          <view\n            :class=\"[nsItem.em('progress', 'wave')]\"\n            :style=\"{ top: `${-300 - item.progress}%` }\"\n          />\n        </view>\n      </slot>\n    </view>\n    <!-- 上传按钮 -->\n    <template v-if=\"!isExceedMaxCount && !disabled\">\n      <slot name=\"uploadBtn\">\n        <view\n          class=\"tn-gray-light_bg tn-gray-disabled_text\"\n          :class=\"[nsItem.b()]\"\n          @tap.stop=\"chooseFile\"\n        >\n          <view :class=\"[nsItem.e('add-btn')]\">\n            <slot name=\"addBtn\">\n              <view :class=\"[nsItem.em('add-btn', 'icon')]\">\n                <TnIcon name=\"add-fill\" />\n              </view>\n            </slot>\n          </view>\n        </view>\n      </slot>\n    </template>\n  </view>\n</template>\n\n<style lang=\"scss\" scoped>\n@import '../../../theme-chalk/src/image-upload.scss';\n</style>\n","import Component from 'C:/Users/35577/Downloads/easyai-uniapp-aigc/src/components/node_modules/@tuniao/tnui-vue3-uniapp/components/image-upload/src/image-upload.vue'\nwx.createComponent(Component)"],"names":["useNamespace","useImageUpload"],"mappings":";;;;;AACA,MAAA,SAAmB,MAAA;;;;;;AAKnB,UAAM,QAAQ;AAGR,UAAA,KAAKA,2BAAa,cAAc;AAChC,UAAA,SAASA,2BAAa,mBAAmB;AAEzC,UAAA;AAAA,MACJ;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,MACA;AAAA,IAAA,IACEC,cAAAA,iBAAe,KAAK;AAEX,aAAA;AAAA;AAAA;AAAA;AAAA,MAIX;AAAA;AAAA;AAAA;AAAA,MAIA,QAAQ;AAAA;AAAA;AAAA;AAAA,MAIR,OAAO;AAAA;AAAA;AAAA;AAAA,MAIP,OAAO;AAAA,IAAA,CACR;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;;ACxCD,GAAG,gBAAgB,SAAS;","x_google_ignoreList":[0]}
